import{_ as a,o as l,c as r,a2 as o}from"./chunks/framework.Bjylvv1V.js";const p=JSON.parse('{"title":"급여 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/payroll.md","filePath":"guide/scenarios/payroll.md","lastUpdated":1771991831000}'),i={name:"guide/scenarios/payroll.md"};function e(n,t,s,d,h,g){return l(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="급여-처리" tabindex="-1">급여 처리 <a class="header-anchor" href="#급여-처리" aria-label="Permalink to &quot;급여 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 30분 | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 매월 (급여 지급일 전)</p></blockquote><p>관리사무소 직원의 월급여를 계산하고, 4대보험·소득세를 공제한 뒤 지급 처리하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 급여 기본정보 확인     (3분)  → 신규/변경 직원 확인</span></span>
<span class="line"><span>2. 급여 계산             (5분)  → 자동 계산 실행</span></span>
<span class="line"><span>3. 급여 명세서 확인      (5분)  → 항목별 검증</span></span>
<span class="line"><span>4. 급여 이체 처리        (5분)  → 은행 이체 실행</span></span>
<span class="line"><span>5. 명세서 배부           (2분)  → 직원에게 전달</span></span>
<span class="line"><span>6. 원천징수 신고         (10분) → 세무 신고</span></span></code></pre></div><hr><h2 id="사전-준비" tabindex="-1">사전 준비 <a class="header-anchor" href="#사전-준비" aria-label="Permalink to &quot;사전 준비&quot;">​</a></h2><h3 id="최초-설정-한-번만" tabindex="-1">최초 설정 (한 번만) <a class="header-anchor" href="#최초-설정-한-번만" aria-label="Permalink to &quot;최초 설정 (한 번만)&quot;">​</a></h3><p>아래 항목은 처음 한 번만 설정하면 됩니다. 변경이 있을 때만 수정합니다.</p><table tabindex="0"><thead><tr><th>설정 항목</th><th>메뉴 경로</th><th>설명</th></tr></thead><tbody><tr><td>급여 코드</td><td><a href="/pay/common.html">공통정보관리</a></td><td>수당·공제 항목 코드</td></tr><tr><td>4대보험 요율</td><td><a href="/pay/common.html">공통정보관리</a></td><td>건강보험·국민연금·고용보험 요율</td></tr><tr><td>소득세율</td><td><a href="/pay/common.html">공통정보관리</a></td><td>근로소득 간이세액표</td></tr></tbody></table><hr><h2 id="_1단계-급여-기본정보-확인-3분" tabindex="-1">1단계: 급여 기본정보 확인 (3분) <a class="header-anchor" href="#_1단계-급여-기본정보-확인-3분" aria-label="Permalink to &quot;1단계: 급여 기본정보 확인 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 급여기본정보 (PAY3010)</p></blockquote><p>직원별 급여 구조가 정확한지 확인합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>급여기본정보 화면 진입</li><li>직원 목록 확인</li><li>각 직원의 탭별 정보 확인:</li></ol><table tabindex="0"><thead><tr><th>탭</th><th>확인 항목</th></tr></thead><tbody><tr><td><strong>기본정보</strong></td><td>기본급, 각종 수당 (0.1 단위 자동 계산)</td></tr><tr><td><strong>건강보험</strong></td><td>보험 번호, 월 보수월액</td></tr><tr><td><strong>고용보험</strong></td><td>가입일</td></tr><tr><td><strong>국민연금</strong></td><td>기준소득월액</td></tr><tr><td><strong>장기기여금</strong></td><td>해당 시</td></tr></tbody></table><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 이번 달 신규 입사자가 등록되어 있는가?</li><li>[ ] 퇴사자는 퇴직 처리가 되었는가?</li><li>[ ] 수당·기본급 변경 사항이 반영되었는가?</li><li>[ ] 4대보험 요율이 올해 기준인가?</li></ul><div class="danger custom-block"><p class="custom-block-title">미등록 직원 제외</p><p>급여기본정보에 등록되지 않은 직원은 급여 계산에서 <strong>자동 제외</strong>됩니다. 반드시 입사 즉시 등록하세요.</p></div><hr><h2 id="_2단계-급여-계산-5분" tabindex="-1">2단계: 급여 계산 (5분) <a class="header-anchor" href="#_2단계-급여-계산-5분" aria-label="Permalink to &quot;2단계: 급여 계산 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 급여계산 (PAY3020)</p></blockquote><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>급여계산 화면 진입</li><li><strong>귀속 연월</strong> 선택 (예: 2026-03)</li><li><strong>계산일</strong> 입력</li><li><strong>계산</strong> 실행 → 시스템이 자동으로 계산: <ul><li><strong>지급 항목</strong>: 기본급 + 각종 수당</li><li><strong>공제 항목</strong>: 소득세 + 4대보험료</li><li><strong>차인 지급액</strong>: 지급 총액 - 공제 총액</li></ul></li><li>계산 결과 확인</li></ol><h3 id="자동-계산-항목" tabindex="-1">자동 계산 항목 <a class="header-anchor" href="#자동-계산-항목" aria-label="Permalink to &quot;자동 계산 항목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>항목</th><th>계산 방식</th></tr></thead><tbody><tr><td><strong>지급</strong></td><td>기본급</td><td>급여기본정보 기준</td></tr><tr><td><strong>지급</strong></td><td>수당</td><td>급여기본정보 기준</td></tr><tr><td><strong>공제</strong></td><td>소득세</td><td>간이세액표 기준</td></tr><tr><td><strong>공제</strong></td><td>지방소득세</td><td>소득세의 10%</td></tr><tr><td><strong>공제</strong></td><td>건강보험</td><td>보수월액 × 요율</td></tr><tr><td><strong>공제</strong></td><td>장기요양보험</td><td>건강보험료 × 요율</td></tr><tr><td><strong>공제</strong></td><td>국민연금</td><td>기준소득 × 요율</td></tr><tr><td><strong>공제</strong></td><td>고용보험</td><td>보수 × 요율</td></tr></tbody></table><h3 id="월-중간-입사자" tabindex="-1">월 중간 입사자 <a class="header-anchor" href="#월-중간-입사자" aria-label="Permalink to &quot;월 중간 입사자&quot;">​</a></h3><p>입사일이 월 중간인 경우 <strong>일할 계산</strong>이 자동 적용됩니다.</p><h3 id="확인-포인트" tabindex="-1">확인 포인트 <a class="header-anchor" href="#확인-포인트" aria-label="Permalink to &quot;확인 포인트&quot;">​</a></h3><ul><li>[ ] 직원 수가 맞는가? (누락/중복 없는지)</li><li>[ ] 기본급이 정확한가?</li><li>[ ] 4대보험 공제액이 합리적인가?</li><li>[ ] 소득세 공제가 정확한가?</li><li>[ ] 차인 지급액(실수령액)이 예상과 일치하는가?</li></ul><div class="warning custom-block"><p class="custom-block-title">계산 확정 후 수정 제한</p><p>급여 계산을 확정하면 수정이 제한됩니다. 확정 전에 반드시 모든 항목을 검증하세요.</p></div><hr><h2 id="_3단계-급여-명세서-확인-5분" tabindex="-1">3단계: 급여 명세서 확인 (5분) <a class="header-anchor" href="#_3단계-급여-명세서-확인-5분" aria-label="Permalink to &quot;3단계: 급여 명세서 확인 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 명세서출력 (PAY3120)</p></blockquote><h3 id="출력-양식" tabindex="-1">출력 양식 <a class="header-anchor" href="#출력-양식" aria-label="Permalink to &quot;출력 양식&quot;">​</a></h3><table tabindex="0"><thead><tr><th>양식</th><th>용도</th></tr></thead><tbody><tr><td><strong>급여명세서</strong></td><td>직원 개인별 상세 내역</td></tr><tr><td><strong>지급대장 A/B</strong></td><td>부서별 요약 (관리용)</td></tr><tr><td><strong>자관한상공증명서</strong></td><td>직원 소득 증빙용</td></tr></tbody></table><h3 id="확인-항목" tabindex="-1">확인 항목 <a class="header-anchor" href="#확인-항목" aria-label="Permalink to &quot;확인 항목&quot;">​</a></h3><p>각 직원의 명세서를 열어 아래를 확인합니다:</p><ul><li>[ ] 지급 항목별 금액이 맞는가?</li><li>[ ] 공제 항목별 금액이 맞는가?</li><li>[ ] 실수령액이 정확한가?</li><li>[ ] 근무일수가 맞는가? (중간 입사/퇴사 시)</li></ul><hr><h2 id="_4단계-급여-이체-처리-5분" tabindex="-1">4단계: 급여 이체 처리 (5분) <a class="header-anchor" href="#_4단계-급여-이체-처리-5분" aria-label="Permalink to &quot;4단계: 급여 이체 처리 (5분)&quot;">​</a></h2><h3 id="이체-목록-출력" tabindex="-1">이체 목록 출력 <a class="header-anchor" href="#이체-목록-출력" aria-label="Permalink to &quot;이체 목록 출력&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 급여이체출력 (PAY3110)</p></blockquote><ol><li>급여이체출력 화면 진입</li><li>직원별 이체 정보 확인: <ul><li>직원명, 은행, 계좌번호, 이체 금액</li></ul></li><li>이체 목록 <strong>출력</strong></li><li>은행에 이체 의뢰 또는 아파트뱅크로 이체 실행</li></ol><h3 id="아파트뱅크-이체-해당-시" tabindex="-1">아파트뱅크 이체 (해당 시) <a class="header-anchor" href="#아파트뱅크-이체-해당-시" aria-label="Permalink to &quot;아파트뱅크 이체 (해당 시)&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 아파트뱅크 &gt; <a href="/bank/transfer.html">이체</a></p></blockquote><ol><li>지출결의서 작성 (BANK1200)</li><li>출금전표 작성 (BANK1070)</li><li>결재 요청 (BANK1080)</li><li>이체 실행 (BANK1090) → 공인인증서 서명</li><li>이체 결과 확인 (BANK1030)</li></ol><div class="warning custom-block"><p class="custom-block-title">잔액 확인</p><p>이체 실행 전에 출금 계좌의 잔액이 충분한지 반드시 확인하세요. 잔액 부족 시 이체가 실패합니다.</p></div><hr><h2 id="_5단계-명세서-배부-2분" tabindex="-1">5단계: 명세서 배부 (2분) <a class="header-anchor" href="#_5단계-명세서-배부-2분" aria-label="Permalink to &quot;5단계: 명세서 배부 (2분)&quot;">​</a></h2><p>직원에게 급여 명세서를 전달합니다.</p><ul><li><strong>이메일/모바일 자동 전송</strong>: 명세서출력 화면에서 자동 발송 옵션 사용</li><li><strong>인쇄 배부</strong>: 출력 후 개인별 교부</li></ul><hr><h2 id="_6단계-원천징수-신고-10분" tabindex="-1">6단계: 원천징수 신고 (10분) <a class="header-anchor" href="#_6단계-원천징수-신고-10분" aria-label="Permalink to &quot;6단계: 원천징수 신고 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 원천징수이행신고서 (PAY3150)</p></blockquote><p>매월 급여에서 원천징수한 세금을 세무서에 신고합니다.</p><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>원천징수이행신고서 화면 진입</li><li>귀속 연월 선택</li><li>항목별 확인 (A01~A40: 급여, 퇴직, 일용직 등)</li><li>신고서 출력</li><li>홈택스(www.hometax.go.kr)에 제출 또는 세무서 방문 제출</li></ol><div class="danger custom-block"><p class="custom-block-title">신고 기한: 다음 달 10일</p><p>원천징수이행신고는 <strong>지급일이 속하는 달의 다음 달 10일</strong>까지 제출해야 합니다. 기한 초과 시 가산세가 부과됩니다.</p></div><hr><h2 id="월별-보험료-확인" tabindex="-1">월별 보험료 확인 <a class="header-anchor" href="#월별-보험료-확인" aria-label="Permalink to &quot;월별 보험료 확인&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/salary.html">급여관리</a> &gt; 월별보험료공제현황 (PAY3130)</p></blockquote><p>직원별 4대보험 공제 내역을 확인합니다:</p><ul><li>건강보험 (본인 + 사업장)</li><li>장기요양보험</li><li>국민연금 (본인 + 사업장)</li><li>고용보험 (본인 + 사업장)</li></ul><hr><h2 id="연말정산-연-1회-1-2월" tabindex="-1">연말정산 (연 1회, 1~2월) <a class="header-anchor" href="#연말정산-연-1회-1-2월" aria-label="Permalink to &quot;연말정산 (연 1회, 1~2월)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a></p></blockquote><p>매년 1~2월에 직원의 연간 소득세를 정산합니다.</p><h3 id="간략-절차" tabindex="-1">간략 절차 <a class="header-anchor" href="#간략-절차" aria-label="Permalink to &quot;간략 절차&quot;">​</a></h3><ol><li><strong>기본정보 등록</strong> → 연도, 사업자번호, 세액 기준</li><li><strong>전직장 내역</strong> (PAY4020) → 중도 입사자의 전직장 원천징수 영수증 입력</li><li><strong>연근로소득 등록</strong> (PAY4010) → 연간 총급여, 비과세소득, 상여 등</li><li><strong>개인공제 등록</strong> (PAY4030) → 부양가족, 보험, 주택자금, 신용카드, 의료비, 교육비, 기부금 <ul><li><strong>홈택스 PDF 연동</strong>: 홈택스에서 소득·세액공제자료 PDF 다운로드 → 시스템 업로드 → 자동 반영</li></ul></li><li><strong>연말정산 실행</strong> (PAY4040) → 최종 세액 계산</li><li><strong>결과 확인</strong> (PAY4041) → 근로소득원천징수영수증 출력</li><li><strong>디스켓 작성</strong> (PAY4050) → 홈택스 제출 파일 생성 (기한: <strong>2월 말</strong>)</li><li><strong>환급/추징</strong> (PAY4060) → 다음 달 급여에 반영</li></ol><div class="warning custom-block"><p class="custom-block-title">개인공제 확인</p><p>홈택스 PDF를 업로드한 후에도 반드시 <strong>각 항목을 직접 확인</strong>하세요. 자동 반영이 정확하지 않을 수 있습니다.</p></div><hr><h2 id="급여-처리-종합-체크리스트" tabindex="-1">급여 처리 종합 체크리스트 <a class="header-anchor" href="#급여-처리-종합-체크리스트" aria-label="Permalink to &quot;급여 처리 종합 체크리스트&quot;">​</a></h2><h3 id="매월" tabindex="-1">매월 <a class="header-anchor" href="#매월" aria-label="Permalink to &quot;매월&quot;">​</a></h3><ul><li>[ ] 신규/퇴사 직원 정보 업데이트</li><li>[ ] 급여 계산 실행 및 검증</li><li>[ ] 명세서 확인 및 배부</li><li>[ ] 이체 처리 및 결과 확인</li><li>[ ] 원천징수 신고 (다음 달 10일까지)</li><li>[ ] 4대보험 공제 내역 확인</li></ul><h3 id="연-1회" tabindex="-1">연 1회 <a class="header-anchor" href="#연-1회" aria-label="Permalink to &quot;연 1회&quot;">​</a></h3><ul><li>[ ] 연말정산 실행 (1~2월)</li><li>[ ] 홈택스 디스켓 제출 (2월 말)</li><li>[ ] 환급/추징 급여 반영</li><li>[ ] 지급명세서 제출 (3월 10일)</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="급여-계산에서-특정-직원이-빠졌어요" tabindex="-1">급여 계산에서 특정 직원이 빠졌어요 <a class="header-anchor" href="#급여-계산에서-특정-직원이-빠졌어요" aria-label="Permalink to &quot;급여 계산에서 특정 직원이 빠졌어요&quot;">​</a></h3><p><strong>원인</strong>: 급여기본정보(PAY3010)에 등록되지 않은 직원 <strong>해결</strong>: 해당 직원을 급여기본정보에 등록한 후 다시 계산하세요.</p><h3 id="_4대보험-공제액이-맞지-않아요" tabindex="-1">4대보험 공제액이 맞지 않아요 <a class="header-anchor" href="#_4대보험-공제액이-맞지-않아요" aria-label="Permalink to &quot;4대보험 공제액이 맞지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 보험 요율이 갱신되지 않았거나, 보수월액이 변경된 경우 <strong>해결</strong>: <a href="/pay/common.html">공통정보관리</a>에서 올해 요율을 확인하고, 급여기본정보의 보수월액을 확인하세요.</p><h3 id="원천징수-신고-기한을-놓쳤어요" tabindex="-1">원천징수 신고 기한을 놓쳤어요 <a class="header-anchor" href="#원천징수-신고-기한을-놓쳤어요" aria-label="Permalink to &quot;원천징수 신고 기한을 놓쳤어요&quot;">​</a></h3><p><strong>원인</strong>: 다음 달 10일 기한 미준수 <strong>해결</strong>: 즉시 신고하세요. 기한 초과 시 가산세가 부과됩니다.</p><h3 id="연말정산에서-홈택스-pdf가-안-올라가요" tabindex="-1">연말정산에서 홈택스 PDF가 안 올라가요 <a class="header-anchor" href="#연말정산에서-홈택스-pdf가-안-올라가요" aria-label="Permalink to &quot;연말정산에서 홈택스 PDF가 안 올라가요&quot;">​</a></h3><p><strong>원인</strong>: PDF 비밀번호 설정, 파일 형식 오류 <strong>해결</strong>: 홈택스에서 PDF를 <strong>비밀번호 없이</strong> 다시 다운로드하세요. 경로: 홈택스 &gt; 조회/발급 &gt; 연말정산 &gt; 소득·세액공제자료 조회 &gt; PDF로 내려받기 (비밀번호 미설정)</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/pay/common.html">공통정보관리</a> - 급여 코드, 보험 요율</li><li><a href="/pay/hr.html">인사관리</a> - 직원 정보</li><li><a href="/pay/salary.html">급여관리</a> - 급여 계산·조회</li><li><a href="/pay/year-end.html">연말정산</a> - 연간 소득세 정산</li><li><a href="/pay/retirement.html">퇴직정산</a> - 퇴직금 정산</li><li><a href="/bank/transfer.html">아파트뱅크 이체</a> - 급여 이체</li></ul>`,91)])])}const u=a(i,[["render",e]]);export{p as __pageData,u as default};
